from flask import Flask, request, session
import xml.etree.ElementTree as ET

app = Flask(__name__)
app.secret_key = 'your_secret_key'

def parse_saml_response(saml_response):
    root = ET.fromstring(saml_response)
    assertion = root.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion')
    if assertion is None:
        raise ValueError("No Assertion found in SAML response")
    
    user_attributes = {}
    for attr in assertion.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Attribute'):
        name = attr.get('Name')
        value = attr.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue').text
        user_attributes[name] = value
    
    return user_attributes

@app.route('/saml/response', methods=['POST'])
def saml_response():
    saml_response = request.form.get('SAMLResponse')
    try:
        user_attributes = parse_saml_response(saml_response)
        session['user'] = user_attributes
        return 'User authenticated and session created'
    except ValueError as e:
        return str(e), 400

if __name__ == '__main__':
    app.run(debug=True)